let cell = 418
let safeInset = 34
let safeSize = 350

guard let sourceImage = NSImage(contentsOf: inputURL),
      let tiff = sourceImage.tiffRepresentation,
      let sourceRep = NSBitmapImageRep(data: tiff) else {
    fputs("failed to read input image: \(inputURL.path)\n", stderr)
    exit(1)
}

guard sourceRep.pixelsWide == sheetWidth, sourceRep.pixelsHigh == sheetHeight else {
    fputs("input must be \(sheetWidth)x\(sheetHeight), got \(sourceRep.pixelsWide)x\(sourceRep.pixelsHigh)\n", stderr)
    exit(1)
}

func colorAtTopLeft(_ x: Int, _ y: Int) -> NSColor {
    // NSBitmapImageRep uses bottom-left coordinates for colorAt.
    sourceRep.colorAt(x: x, y: sheetHeight - 1 - y) ?? .white
}

func isArtwork(_ color: NSColor) -> Bool {
    guard let rgb = color.usingColorSpace(.deviceRGB) else { return false }
    if rgb.alphaComponent < 0.05 { return false }
    let r = rgb.redComponent * 255
    let g = rgb.greenComponent * 255
    let b = rgb.blueComponent * 255
    // White sheet background and antialiased near-white pixels are not content.
    return min(255 - r, min(255 - g, 255 - b)) > 14
}

func artworkBox(cellX: Int, cellY: Int) -> Box? {
    var box: Box?
    for y in 0..<cell {
        for x in 0..<cell {
            if isArtwork(colorAtTopLeft(cellX + x, cellY + y)) {
                if var current = box {
                    current.minX = min(current.minX, x)
                    current.minY = min(current.minY, y)
                    current.maxX = max(current.maxX, x)
                    current.maxY = max(current.maxY, y)
                    box = current
                } else {
                    box = Box(minX: x, minY: y, maxX: x, maxY: y)
                }
            }
        }
    }
    return box
}

